export type ParsedPurchaseSkillInstruction<
  TProgram extends string = typeof AGENC_COORDINATION_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    skill: TAccountMetas[0];
    purchaseRecord: TAccountMetas[1];
    buyer: TAccountMetas[2];
    /** Skill author's agent registration */
    authorAgent: TAccountMetas[3];
    authorWallet: TAccountMetas[4];
    protocolConfig: TAccountMetas[5];
    treasury: TAccountMetas[6];
    authority: TAccountMetas[7];
    systemProgram: TAccountMetas[8];
    /** SPL token mint for price denomination (optional) */
    priceMint?: TAccountMetas[9] | undefined;
    /** Buyer's token account (optional) */
    buyerTokenAccount?: TAccountMetas[10] | undefined;
    /** Author's token account (optional) */
    authorTokenAccount?: TAccountMetas[11] | undefined;
    /** Treasury's token account (optional) */
    treasuryTokenAccount?: TAccountMetas[12] | undefined;
    /** SPL Token program (optional) */
    tokenProgram?: TAccountMetas[13] | undefined;
  };
  data: PurchaseSkillInstructionData;
};

export function parsePurchaseSkillInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedPurchaseSkillInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 14) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 14,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === AGENC_COORDINATION_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      skill: getNextAccount(),
      purchaseRecord: getNextAccount(),
      buyer: getNextAccount(),
      authorAgent: getNextAccount(),
      authorWallet: getNextAccount(),
      protocolConfig: getNextAccount(),
      treasury: getNextAccount(),
      authority: getNextAccount(),
      systemProgram: getNextAccount(),
      priceMint: getNextOptionalAccount(),
      buyerTokenAccount: getNextOptionalAccount(),
      authorTokenAccount: getNextOptionalAccount(),
      treasuryTokenAccount: getNextOptionalAccount(),
      tokenProgram: getNextOptionalAccount(),
    },
    data: getPurchaseSkillInstructionDataDecoder().decode(instruction.data),
  };
}
